define("tool_eledia_mailtemplates/preview",["core/ajax","core/notification"],function(Ajax,Notification){"use strict";var debounceTimer=null;var updateVariablesList=function(type){var container=document.getElementById("tool-mt-variables-list");if(!container){return;}if(!type){container.innerHTML="<em>Select a notification type to see available variables.</em>";return;}Ajax.call([{methodname:"tool_eledia_mailtemplates_get_type_variables",args:{notification_type:type}}])[0].then(function(result){if(!result.variables||result.variables.length===0){container.innerHTML="<em>No variables available for this type.</em>";return;}var chips=result.variables.map(function(v){return"<code title=\""+v.description+"\" style=\"cursor:pointer;margin:2px;display:inline-block;\" onclick=\"navigator.clipboard.writeText('"+v.placeholder+"')\">"+v.placeholder+"</code>";}).join(" ");container.innerHTML=chips+"<div style=\"font-size:0.85em;color:#666;margin-top:4px;\">Click to copy</div>";}).catch(Notification.exception);};var getEditorContent=function(){var attoFrame=document.querySelector("[id$=\"_body_html_editor\"] iframe");if(attoFrame&&attoFrame.contentDocument){return attoFrame.contentDocument.body.innerHTML;}if(typeof window.tinymce!=="undefined"){var editor=window.tinymce.get("id_body_html");if(editor){return editor.getContent();}}var textarea=document.getElementById("id_body_html");return textarea?textarea.value:"";};var renderPreview=function(){var typeSelect=document.getElementById("id_notification_type");var subjectInput=document.getElementById("id_subject");var previewContainer=document.getElementById("tool-mt-preview");if(!typeSelect||!subjectInput||!previewContainer){return;}var type=typeSelect.value;if(!type){previewContainer.innerHTML="<em>Select a notification type to see the preview.</em>";return;}var bodyHtml=getEditorContent();if(!bodyHtml){previewContainer.innerHTML="<em>Enter template content to see the preview.</em>";return;}Ajax.call([{methodname:"tool_eledia_mailtemplates_render_preview",args:{notification_type:type,subject:subjectInput.value,body_html:bodyHtml}}])[0].then(function(result){previewContainer.innerHTML="<div style=\"margin-bottom:8px;font-weight:bold;color:#333;font-size:0.95em;\">Subject: "+result.subject+"</div><div style=\"border:1px solid #ddd;padding:16px;background:#fff;\">"+result.body_html+"</div>";}).catch(Notification.exception);};var debouncedPreview=function(){if(debounceTimer){clearTimeout(debounceTimer);}debounceTimer=setTimeout(renderPreview,800);};return{init:function(){var typeSelect=document.getElementById("id_notification_type");if(typeSelect){typeSelect.addEventListener("change",function(){updateVariablesList(typeSelect.value);debouncedPreview();});if(typeSelect.value){updateVariablesList(typeSelect.value);debouncedPreview();}}var subjectInput=document.getElementById("id_subject");if(subjectInput){subjectInput.addEventListener("input",debouncedPreview);}setInterval(debouncedPreview,3000);}};});
